+
+/// Event kinds for stdio evidence rows.
+#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
+#[serde(rename_all = "snake_case")]
+pub enum StdioEventKind {
+    StreamAcquired,
+    StreamReleased,
+    Read,
+    Write,
+    Seek,
+    Tell,
+    Flush,
+    Ungetc,
+    StatusQuery,
+    ClearError,
+    ForeignAdoption,
+    HealingTriggered,
+    PomdpRepair,
+}
+
+/// Origin of the observed FILE pointer.
+#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
+#[serde(rename_all = "snake_case")]
+pub enum FpOrigin {
+    Native,
+    Foreign,
