+            pid: std::process::id(),
+            tid,
+            comm: std::fs::read_to_string("/proc/self/comm")
+                .ok()
+                .map(|comm| comm.trim().to_string())
+                .filter(|comm| !comm.is_empty()),
+        }
+    }
+}
